'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { Input, NeonButton, GlassCard } from '@/components/ui';
import { authService } from '@/lib/auth/authService';
import { loginSchema, type LoginInput } from '@/lib/validation/schemas';
import { AppError } from '@/types';
import { logger } from '@/lib/utils/logger';

export default function LoginPage() {
  const router = useRouter();
  const [formData, setFormData] = useState<LoginInput>({
    email: '',
    password: '',
    rememberMe: false
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);
  const [generalError, setGeneralError] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    const fieldValue = type === 'checkbox' ? checked : value;

    setFormData(prev => ({ ...prev, [name]: fieldValue }));

    // Real-time validation
    try {
      loginSchema.pick({ [name]: true } as any).parse({ [name]: fieldValue });
      setErrors(prev => ({ ...prev, [name]: '' }));
    } catch (error: any) {
      if (error.errors?.[0]) {
        setErrors(prev => ({ ...prev, [name]: error.errors[0].message }));
      }
    }

    if (generalError) {
      setGeneralError('');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validate with Zod
    const result = loginSchema.safeParse(formData);

    if (!result.success) {
      const fieldErrors: Record<string, string> = {};
      result.error.errors.forEach(err => {
        if (err.path[0]) {
          fieldErrors[err.path[0].toString()] = err.message;
        }
      });
      setErrors(fieldErrors);
      logger.warn('Login form validation failed', { errors: fieldErrors });
      return;
    }

    setIsLoading(true);
    setGeneralError('');

    try {
      await authService.login({ email: result.data.email, password: result.data.password });
      logger.info('User logged in successfully', { email: result.data.email });
      router.push('/');
    } catch (error: any) {
      const appError = error as AppError;
      setGeneralError(appError.message || 'Login failed. Please try again.');
      logger.error('Login failed', error as Error, { email: formData.email });
    } finally {
      setIsLoading(false);
    }
  };

